import React, { useState, useEffect } from 'react';
import './Certificates.css';

interface Certificate {
  _id?: string;
  title: string;
  issuer: string;
  date: string;
  credentialId: string;
  credentialUrl: string;
  imageUrl: string;
  score?: string;
  assessments?: string;
  description?: string;
}

const Certificates: React.FC = () => {
  const [certificates, setCertificates] = useState<Certificate[]>([
    {
      title: 'The Joy of Computing using Python',
      issuer: 'NPTEL · IIT Madras',
      date: '2021',
      credentialId: 'Elite certificate (NPTEL Online Certification)',
      credentialUrl: 'https://nptel.ac.in/certificate',
      imageUrl: '/python-nptel-certificate.jpg',
      score: 'Consolidated score: 69%',
      assessments: 'Online Assignments: 23.94/25, Programming Exam: 25/25, Proctored Exam: 20/50',
      description: 'Built strong foundations in Python programming and computational thinking through graded assignments and exams.'
    }
  ]);

  // Using local certificate data only

  const handleImageError = (e: React.SyntheticEvent<HTMLImageElement>) => {
    const target = e.target as HTMLImageElement;
    target.src = 'data:image/svg+xml;base64,';
  };

  return (
    <div className="certificates">
      <div className="container">
        <h1 className="page-title">My Certificates</h1>
        <p className="page-subtitle">
          Professional certifications and achievements that showcase my continuous learning and expertise in various technologies.
        </p>

        <div className="certificates-grid">
          {certificates.map((certificate, index) => (
            <div key={certificate._id || index} className="certificate-card">
              <div className="certificate-image" onClick={() => window.open(certificate.imageUrl, '_blank')}>
                <img 
                  src={certificate.imageUrl} 
                  alt={certificate.title}
                  onError={handleImageError}
                  style={{ cursor: 'pointer' }}
                />
              </div>

              <div className="certificate-content">
                <h3>{certificate.title}</h3>
                <div className="certificate-meta">
                  <div className="issuer">
                    <strong>Issuer:</strong> {certificate.issuer}
                  </div>
                  <div className="date">
                    <strong>Date:</strong> {certificate.date}
                  </div>
                  {certificate.credentialId && (
                    <div className="credential-id">
                      <strong>ID:</strong> {certificate.credentialId}
                    </div>
                  )}
                  {certificate.score && (
                    <div className="score">
                      <strong>Score:</strong> {certificate.score}
                    </div>
                  )}
                </div>

                {certificate.assessments && (
                  <div className="assessments">
                    <strong>Assessments:</strong> {certificate.assessments}
                  </div>
                )}

                {certificate.description && (
                  <div className="certificate-description">
                    {certificate.description}
                  </div>
                )}

                <div className="certificate-actions">
                  <a 
                    href={certificate.credentialUrl} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="btn btn-primary"
                  >
                    Verify Certificate
                  </a>
                </div>
              </div>
            </div>
          ))}
        </div>

        {certificates.length === 0 && (
          <div className="no-certificates">
            <p>No certificates available at the moment.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Certificates;
